// Fan-out from same trigger — A1 and A2 both receive QuestionnaireCompleted
// Neither needs the other's output — run in parallel, not sequential
// A3 depends on A1's output (BusinessProfileCreated), not on QuestionnaireCompleted
// WRONG: chain A1→A2→A3 sequentially — A2 waits for A1 even though it uses raw answers
// CORRECT:
async function runTier1(event: QuestionnaireCompleted) {
  const [a1Result, a2Result] = await Promise.all([
    this.buildBusinessProfile(event),    // A1: structured profile
    this.analyzeSegment(event),          // A2: raw questionnaire analytics
  ]);
  // A3 waits for A1's output — triggers on BusinessProfileCreated
  if (a1Result.isSuccess) {
    await this.generateLearningProgram(a1Result.data.profileId);
  }
}
